// Extract relevant fields from Notion record
const items = $input.all();
const results = [];

for (const item of items) {
  const props = item.json.properties || item.json;

  // Extract properties - adapt property names to your Notion DB schema
  const pageId = item.json.id || item.json.pageId || '';
  const titulo = props.Titulo?.title?.[0]?.plain_text
    || props.Titulo?.title?.[0]?.text?.content
    || props.titulo?.title?.[0]?.plain_text
    || props.Name?.title?.[0]?.plain_text
    || 'Sin titulo';

  const descripcion = props.Descripcion?.rich_text?.[0]?.plain_text
    || props.descripcion?.rich_text?.[0]?.plain_text
    || props.Brief?.rich_text?.[0]?.plain_text
    || '';

  const canal = props.Canal?.select?.name
    || props.canal?.select?.name
    || props.Red_Social?.select?.name
    || 'General';

  const targetAudience = props.Target_Audience?.rich_text?.[0]?.plain_text
    || props.Audiencia?.rich_text?.[0]?.plain_text
    || props.audiencia?.rich_text?.[0]?.plain_text
    || 'Ecosistema fintech Chile';

  const responsable = props.Responsable?.people?.[0]?.name
    || props.responsable?.people?.[0]?.name
    || '';

  const responsableEmail = props.Responsable?.people?.[0]?.person?.email
    || props.responsable?.people?.[0]?.person?.email
    || '';

  const notionUrl = item.json.url || `https://www.notion.so/${pageId.replace(/-/g, '')}`;

  results.push({
    json: {
      pageId,
      titulo,
      descripcion,
      canal,
      targetAudience,
      responsable,
      responsableEmail,
      notionUrl
    }
  });
}

return results;

