// Format the AI-generated variants into a clean structure
const input = $input.first().json;
const previousData = $('Extract Content Fields').first().json;

let variantes = [];
let rawResponse = '';

try {
  // Extract content from OpenAI response
  const content = input.choices?.[0]?.message?.content || '';
  rawResponse = content;

  // Try parsing JSON from the response
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    variantes = parsed.variantes || parsed.variants || [];
  }
} catch (e) {
  // If JSON parsing fails, split by variant markers
  variantes = [
    { numero: 1, texto: rawResponse, hashtags: '', cta: 'Parsing failed - review raw response' }
  ];
}

// Build formatted text for email and Notion
let formattedForEmail = '';
let formattedForNotion = '';

variantes.forEach((v, i) => {
  const num = v.numero || (i + 1);
  formattedForEmail += `<h3>Variante ${num}</h3>`;
  formattedForEmail += `<p>${(v.texto || '').replace(/\n/g, '<br>')}</p>`;
  formattedForEmail += `<p><strong>Hashtags:</strong> ${v.hashtags || 'N/A'}</p>`;
  formattedForEmail += `<p><strong>CTA:</strong> ${v.cta || 'N/A'}</p>`;
  formattedForEmail += '<hr>';

  formattedForNotion += `--- Variante ${num} ---\n`;
  formattedForNotion += `${v.texto || ''}\n`;
  formattedForNotion += `Hashtags: ${v.hashtags || 'N/A'}\n`;
  formattedForNotion += `CTA: ${v.cta || 'N/A'}\n\n`;
});

const now = new Date().toISOString();

return [{
  json: {
    ...previousData,
    variantes,
    variantesCount: variantes.length,
    formattedForEmail,
    formattedForNotion: formattedForNotion.trim(),
    rawAiResponse: rawResponse,
    generatedAt: now
  }
}];

